from langgraph.graph import StateGraph
from langgraph.checkpoint.sqlite import SqliteSaver
from collections import defaultdict, deque

class LoopDetector:
    def __init__(self, max_cycles=5):
        self.max_cycles = max_cycles
        self.node_history = deque(maxlen=100)
        self.cycle_counts = defaultdict(int)

    def check_loop(self, state):
        current_node = state.get('__node_history__', [])[-1] if state.get('__node_history__') else 'unknown'
        self.node_history.append(current_node)

        # Check for repeating sequence
        recent_history = list(self.node_history)[-self.max_cycles*2:]
        sequence = tuple(recent_history[-self.max_cycles:])

        if sequence in [tuple(list(self.node_history)[i:i+self.max_cycles]) for i in range(len(self.node_history)-self.max_cycles*2, len(self.node_history)-self.max_cycles)]:
            return {'loop_detected': True, 'cycle': str(sequence)}
        return {'loop_detected': False}

# Usage in graph
loop_detector = LoopDetector()
def loop_check_node(state):
    detection = loop_detector.check_loop(state)
    if detection['loop_detected']:
        return {'error': f'Tool loop detected: {detection["cycle"]}'}
    return state

from langgraph.prebuilt import ToolNode
import hashlib

class ToolLoopTracker(ToolNode):
    def __init__(self, tools, max_repeats=3):
        super().__init__(tools)
        self.tool_calls = {}

    def _track_call(self, tool_name, args):
        call_sig = f'{tool_name}:{hashlib.md5(str(args).encode()).hexdigest()}'
        self.tool_calls.setdefault(call_sig, 0)
        self.tool_calls[call_sig] += 1
        return self.tool_calls[call_sig] > 3

    async def invoke(self, state):
        messages = state['messages']
        tool_calls = messages[-1].tool_calls if hasattr(messages[-1], 'tool_calls') else []

        for call in tool_calls:
            if self._track_call(call['name'], call['args']):
                return {'messages': [{'role': 'system', 'content': f'Tool loop detected: {call["name"]} called 4+ times with same args'}]}

        return await super().invoke(state)

