from langgraph.graph import END, StateGraph

class CycleBreaker:
    def __init__(self, max_tool_calls=5):
        self.tool_counts = defaultdict(int)

    def should_break(self, state):
        messages = state['messages']
        recent_tools = [m for m in messages[-10:] if m.tool_calls]
        tool_names = [call[0]['name'] for m in recent_tools for call in m.tool_calls]

        for tool in set(tool_names):
            count = tool_names.count(tool)
            if count >= max_tool_calls:
                return True, f'Max tool calls exceeded for {tool}'
        return False, None

cycle_breaker = CycleBreaker()

def break_loop_node(state):
    should_break, reason = cycle_breaker.should_break(state)
    if should_break:
        return {'messages': [{'role': 'system', 'content': f'INTERRUPTED: {reason}'}], 'interrupted': True}
    return state

# Add to graph
graph.add_node('break_loop', break_loop_node)
graph.add_conditional_edges(
    'agent',
    lambda state: 'break_loop' if cycle_breaker.should_break(state)[0] else 'tools',
    {'break_loop': END, 'tools': 'tools'}
)

